def make_cache_key_from_request(req, include_headers: Optional[Tuple[str, ...]] = None) -> str:
    parts = [
        req.method.upper(),
        req.path,
        req.query_string.decode("utf-8", "ignore"),
    ]
    if include_headers:
        for h in include_headers:
            parts.append(f"{h.lower()}={req.headers.get(h,'')}")
    return "|".join(parts)


